// DATA PARSER V3
function extractById(batchResponse, id) {
  if (!batchResponse) return null;
  const data = batchResponse.data ?? batchResponse;
  if (!Array.isArray(data)) return null;
  const entry = data.find(d => d.id === id);
  return entry?.result ?? null;
}

function safeNum(val) {
  if (val === null || val === undefined) return null;
  const n = Number(val);
  return isNaN(n) ? null : n;
}

const items = $input.all();
let batch4h = null, batch1h = null;
for (const item of items) {
  const data = item.json?.data ?? item.json;
  if (!Array.isArray(data)) continue;
  const ids = data.map(d => d.id).join(',');
  if (ids.includes('4h')) batch4h = item.json;
  if (ids.includes('1h')) batch1h = item.json;
}

const supertrend4h = extractById(batch4h, 'supertrend_4h');
const supertrendDirection = supertrend4h?.valueAdvice?.toUpperCase() ?? null;
const ema50 = safeNum(extractById(batch4h, 'ema_50_4h')?.value);
const atr4h = safeNum(extractById(batch4h, 'atr_4h')?.value);

const candle4h = extractById(batch4h, 'candle_4h');
const candle4hPrev = extractById(batch4h, 'candle_4h_prev');
const currentPrice = safeNum(candle4h?.close);
const volume = safeNum(candle4h?.volume);
const prevVolume = safeNum(candle4hPrev?.volume);
const volumeAbovePrev = (volume !== null && prevVolume !== null && prevVolume > 0) ? volume > prevVolume : null;

const macd4hCurrent = extractById(batch4h, 'macd_4h_current');
const macd4hPrev = extractById(batch4h, 'macd_4h_prev');
const macd4h = {
  value: safeNum(macd4hCurrent?.valueMACD),
  signal: safeNum(macd4hCurrent?.valueMACDSignal),
  histogram: safeNum(macd4hCurrent?.valueMACDHist),
  prevHistogram: safeNum(macd4hPrev?.valueMACDHist),
  prevValue: safeNum(macd4hPrev?.valueMACD),
  prevSignal: safeNum(macd4hPrev?.valueMACDSignal)
};

const adx4h = safeNum(extractById(batch4h, 'adx_4h')?.adx);
const rsi4h = safeNum(extractById(batch4h, 'rsi_4h_current')?.value);
const rsi4hPrev = safeNum(extractById(batch4h, 'rsi_4h_prev')?.value);
const atrPercent = (atr4h !== null && currentPrice !== null && currentPrice > 0) ? (atr4h / currentPrice * 100) : null;

const macd1hCurrent = extractById(batch1h, 'macd_1h_current');
const macd1hPrev = extractById(batch1h, 'macd_1h_prev');
const macd1h = {
  value: safeNum(macd1hCurrent?.valueMACD),
  signal: safeNum(macd1hCurrent?.valueMACDSignal),
  histogram: safeNum(macd1hCurrent?.valueMACDHist),
  prevHistogram: safeNum(macd1hPrev?.valueMACDHist)
};
const atr1h = safeNum(extractById(batch1h, 'atr_1h')?.value);
const rsi1h = safeNum(extractById(batch1h, 'rsi_1h_current')?.value);
const rsi1hPrev = safeNum(extractById(batch1h, 'rsi_1h_prev')?.value);
const cci1h = safeNum(extractById(batch1h, 'cci_1h')?.value);
const adx1h = safeNum(extractById(batch1h, 'adx_1h')?.value);

function macdColor(hist, prevHist) {
  if (hist === null || prevHist === null) return 'UNKNOWN';
  if (hist > 0 && hist > prevHist) return 'AQUA';
  if (hist > 0 && hist <= prevHist) return 'BLUE';
  if (hist <= 0 && hist < prevHist) return 'RED';
  if (hist <= 0 && hist >= prevHist) return 'MAROON';
  return 'UNKNOWN';
}

const macd4hColor = macdColor(macd4h.histogram, macd4h.prevHistogram);
const macd1hColor = macdColor(macd1h.histogram, macd1h.prevHistogram);

const missingData = [];
if (!supertrendDirection) missingData.push('supertrend_4h');
if (ema50 === null) missingData.push('ema50_4h');
if (macd4h.histogram === null) missingData.push('macd_4h');
if (macd1h.histogram === null) missingData.push('macd_1h');
if (atr4h === null) missingData.push('atr_4h');
if (atr1h === null) missingData.push('atr_1h');
if (rsi1h === null) missingData.push('rsi_1h');
if (rsi1hPrev === null) missingData.push('rsi_1h_prev');
if (cci1h === null) missingData.push('cci_1h');
if (adx1h === null) missingData.push('adx_1h');
if (currentPrice === null) missingData.push('current_price');

const symbolPair = items[0]?.json?.symbolPair || items[0]?.json?.symbol || 'UNKNOWN';
const asset = symbolPair.replace('/USDT', '');

return [{ json: {
  asset, currentPrice,
  timestamp: new Date().toISOString(),
  supertrend: supertrendDirection,
  ema50, atr4h, atr1h,
  volume, prevVolume, volumeAbovePrev,
  macd4h, macd4hColor, macd1h, macd1hColor,
  adx4h, rsi4h, rsi4hPrev, atrPercent,
  rsi1h, rsi1hPrev, cci1h, adx1h,
  missingData
} }];

// SIGNAL ENGINE V3b + SCALP V5
const d = $input.first().json;

const critical = ['supertrend_4h', 'ema50_4h', 'macd_4h', 'macd_1h', 'atr_4h', 'atr_1h', 'rsi_1h', 'rsi_1h_prev', 'cci_1h', 'adx_1h', 'current_price'];
const missingCritical = (d.missingData || []).filter(m => critical.includes(m));
if (missingCritical.length > 0) {
  return [{ json: { ...d, signal: 'NO_TRADE', signalType: null, signalReason: 'Fehlende Daten: ' + missingCritical.join(', ') } }];
}

const price = d.currentPrice;
const st = d.supertrend;
const ema50 = d.ema50;
const volWarning = d.volumeAbovePrev === false;

let signal = 'NO_TRADE';
let signalType = null;
let signalReason = '';

// SCALP V5: RSI Momentum Burst
const rsi1h = d.rsi1h;
const rsi1hPrev = d.rsi1hPrev;
const cci1h = d.cci1h;
const adx1h = d.adx1h;

if (rsi1h !== null && rsi1hPrev !== null && cci1h !== null && adx1h !== null) {
  if (rsi1hPrev < 55 && rsi1h >= 55 && cci1h > 0 && adx1h > 20) {
    signal = 'LONG'; signalType = 'SCALP';
    signalReason = 'RSI kreuzt 55 auf (' + rsi1hPrev.toFixed(1) + '->' + rsi1h.toFixed(1) + ') CCI(' + cci1h.toFixed(0) + ')>0 ADX(' + adx1h.toFixed(1) + ')>20';
  }
  if (rsi1hPrev > 45 && rsi1h <= 45 && cci1h < 0 && adx1h > 20) {
    signal = 'SHORT'; signalType = 'SCALP';
    signalReason = 'RSI kreuzt 45 ab (' + rsi1hPrev.toFixed(1) + '->' + rsi1h.toFixed(1) + ') CCI(' + cci1h.toFixed(0) + ')<0 ADX(' + adx1h.toFixed(1) + ')>20';
  }
}

// SWING V3b
if (signal === 'NO_TRADE') {
  const adx4h = d.adx4h;
  const rsi4h = d.rsi4h;
  const macdHist = d.macd4h ? d.macd4h.histogram : null;
  const macdPrevHist = d.macd4h ? d.macd4h.prevHistogram : null;
  const atrPct = d.atrPercent;

  if (atrPct !== null && atrPct > 5.0) {
    signalReason = 'ATR% ' + atrPct.toFixed(1) + '% > 5% zu volatil';
  } else if (adx4h === null || adx4h < 20) {
    signalReason = 'ADX(' + (adx4h ? adx4h.toFixed(1) : '?') + ') < 20';
  } else if (st === 'LONG' && price > ema50 && rsi4h !== null && rsi4h >= 40 && rsi4h <= 65 && macdHist !== null && macdPrevHist !== null && macdHist > macdPrevHist && macdPrevHist <= 0) {
    signal = 'LONG'; signalType = 'SWING';
    signalReason = 'ST LONG + >EMA50 + ADX(' + adx4h.toFixed(1) + ') + RSI(' + rsi4h.toFixed(1) + ') + MACD Zero-Cross';
  } else if (st === 'SHORT' && price < ema50 && rsi4h !== null && rsi4h >= 35 && rsi4h <= 60 && macdHist !== null && macdPrevHist !== null && macdHist < macdPrevHist && macdPrevHist >= 0) {
    signal = 'SHORT'; signalType = 'SWING';
    signalReason = 'ST SHORT + <EMA50 + ADX(' + adx4h.toFixed(1) + ') + RSI(' + rsi4h.toFixed(1) + ') + MACD Zero-Cross';
  }

  if (signal !== 'NO_TRADE' && signalType === 'SWING') {
    const staticData = $getWorkflowStaticData('global');
    const lastKey = d.asset + '_' + signal + '_SWING_last';
    const lastTime = staticData[lastKey] || 0;
    if (Date.now() - lastTime < 12 * 60 * 60 * 1000) {
      signalReason = 'Duplikat-Schutz: ' + signal + ' < 12h'; signal = 'NO_TRADE'; signalType = null;
    } else { staticData[lastKey] = Date.now(); }
  }
}

if (signal === 'NO_TRADE' && !signalReason) signalReason = 'Keine Bedingung (ST:' + st + ')';
return [{ json: { ...d, signal, signalType, signalReason: signalReason + (volWarning ? ' (low vol)' : '') } }];

// ENTRY CALCULATOR V3.5
const d = $input.first().json;
if (d.signal === 'NO_TRADE') return [{ json: { ...d, trade: false } }];

const price = d.currentPrice;
const isLong = d.signal === 'LONG';
const isScalp = d.signalType === 'SCALP';
const atr = isScalp ? d.atr1h : d.atr4h;
const ema50 = d.ema50;

function roundPrice(p) {
  if (!p || isNaN(p)) return null;
  if (p > 10000) return Math.round(p / 50) * 50;
  if (p > 1000) return Math.round(p / 10) * 10;
  if (p > 100) return Math.round(p);
  if (p > 10) return Math.round(p * 2) / 2;
  if (p > 1) return Math.round(p * 100) / 100;
  if (p > 0.01) return Math.round(p * 1000) / 1000;
  return Math.round(p * 100000) / 100000;
}

if (!atr || atr <= 0) return [{ json: { ...d, trade: false } }];

let entry;
if (isScalp) {
  entry = isLong ? price - price * 0.0015 : price + price * 0.0015;
} else {
  entry = isLong ? price - price * 0.003 : price + price * 0.003;
  if (ema50) {
    const dist = Math.abs((ema50 - price) / price);
    if ((isLong && ema50 < entry && dist <= 0.015) || (!isLong && ema50 > entry && dist <= 0.015)) entry = ema50;
  }
}

const slMult = isScalp ? 1.0 : 1.5;
const tp1Mult = isScalp ? 1.5 : 2.0;
const tp2Mult = isScalp ? 2.5 : 3.0;
const stopLoss = isLong ? entry - slMult * atr : entry + slMult * atr;
const tp1 = isLong ? entry + tp1Mult * atr : entry - tp1Mult * atr;
const tp2 = isLong ? entry + tp2Mult * atr : entry - tp2Mult * atr;

if (Math.abs(tp1 - entry) <= 0) return [{ json: { ...d, trade: false } }];

return [{ json: { ...d, trade: true, setup: { type: d.signalType, direction: d.signal, entry: roundPrice(entry), stopLoss: roundPrice(stopLoss), tp1: roundPrice(tp1), tp2: roundPrice(tp2), leverage: isScalp ? 3 : 2, atrUsed: Math.round(atr * 100) / 100 } } }];

// SAVE TO SUPABASE signal_tracker
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InVmb3piYWRodWdkcGF1a3Z2aXRtIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NDU3Nzc5NCwiZXhwIjoyMDkwMTUzNzk0fQ.av7188oiVd-viUAHQDhzb7H7xeHUV5x00NkUph3WWa4';

const d = $input.first().json;
const s = d.setup;
const isScalp = s.type === 'SCALP';
const expiresAt = new Date(Date.now() + (isScalp ? 1 : 48) * 60 * 60 * 1000).toISOString();

try {
  const resp = await fetch('https://ufozbadhugdpaukvvitm.supabase.co/rest/v1/signal_tracker', {
    method: 'POST',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify({
      coin: d.asset,
      direction: s.direction,
      signal_type: s.type,
      entry_price: s.entry,
      tp1_price: s.tp1,
      tp2_price: s.tp2 || s.tp1,
      sl_price: s.stopLoss,
      current_price: d.currentPrice,
      leverage: s.leverage,
      atr_used: s.atrUsed,
      signal_reason: d.signalReason,
      status: 'ACTIVE',
      expires_at: expiresAt
    })
  });
  const result = await resp.json();
  return [{ json: { saved: true, signal: result, asset: d.asset, type: s.type, direction: s.direction } }];
} catch(e) {
  return [{ json: { saved: false, error: e.message, asset: d.asset } }];
}

// PRICE CHECK - Check active signals in signal_tracker
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InVmb3piYWRodWdkcGF1a3Z2aXRtIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NDU3Nzc5NCwiZXhwIjoyMDkwMTUzNzk0fQ.av7188oiVd-viUAHQDhzb7H7xeHUV5x00NkUph3WWa4';
const TAAPI_SECRET = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJjbHVlIjoiNjk3OGIyZGNhZWVjODgxNjBhNDc0ODFkIiwiaWF0IjoxNzczNjQ4ODE1LCJleHAiOjMzMjc4MTEyODE1fQ.DuKPlzcpTH7BRkLZZ2WRH3YupMM-P7hE9lSx35AzUZA';

const closedTrades = [];
const errors = [];

let trades = [];
try {
  const resp = await fetch('https://ufozbadhugdpaukvvitm.supabase.co/rest/v1/signal_tracker?or=(status.eq.ACTIVE,status.eq.TP1_HIT)&order=created_at.desc', {
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  trades = await resp.json();
  if (!Array.isArray(trades)) { errors.push('Supabase: ' + JSON.stringify(trades).substring(0, 200)); trades = []; }
} catch(e) { errors.push('Supabase: ' + e.message); }

if (trades.length === 0) {
  return [{ json: { message: 'Keine offenen Trades', closedTrades: [], errors } }];
}

const uniqueCoins = [...new Set(trades.map(t => t.coin))];
const priceMap = {};

for (const coin of uniqueCoins) {
  try {
    const resp = await fetch('https://api.taapi.io/candle?secret=' + TAAPI_SECRET + '&exchange=binancefutures&symbol=' + coin + '/USDT&interval=1h');
    const data = await resp.json();
    if (data.close) priceMap[coin] = { close: data.close, high: data.high, low: data.low };
    else errors.push('No price: ' + coin);
    await new Promise(r => setTimeout(r, 500));
  } catch(e) { errors.push(coin + ': ' + e.message); }
}

for (const trade of trades) {
  const p = priceMap[trade.coin];
  if (!p) continue;

  const isLong = trade.direction === 'LONG';
  let newStatus = null;

  if (isLong && p.low <= trade.sl_price) newStatus = 'SL_HIT';
  if (!isLong && p.high >= trade.sl_price) newStatus = 'SL_HIT';

  if (!newStatus && trade.status === 'TP1_HIT') {
    if (isLong && p.high >= trade.tp2_price) newStatus = 'TP2_HIT';
    if (!isLong && p.low <= trade.tp2_price) newStatus = 'TP2_HIT';
  }

  if (!newStatus && trade.status === 'ACTIVE') {
    if (isLong && p.high >= trade.tp1_price) newStatus = 'TP1_HIT';
    if (!isLong && p.low <= trade.tp1_price) newStatus = 'TP1_HIT';
  }

  if (!newStatus && new Date() > new Date(trade.expires_at)) newStatus = 'EXPIRED';

  if (newStatus) {
    let pnl = 0;
    const entry = trade.entry_price;
    const lev = trade.leverage || 2;

    if (newStatus === 'TP1_HIT') pnl = Math.abs(trade.tp1_price - entry) / entry * 100 * lev * 0.6;
    else if (newStatus === 'TP2_HIT') {
      pnl = Math.abs(trade.tp1_price - entry) / entry * 100 * lev * 0.6 + Math.abs(trade.tp2_price - entry) / entry * 100 * lev * 0.4;
    } else if (newStatus === 'SL_HIT') pnl = -(Math.abs(trade.sl_price - entry) / entry * 100 * lev);

    const updateData = { status: newStatus, pnl_pct: Math.round(pnl * 100) / 100 };
    if (newStatus === 'TP1_HIT') updateData.tp1_hit_at = new Date().toISOString();
    if (newStatus === 'TP2_HIT') updateData.tp2_hit_at = new Date().toISOString();
    if (newStatus !== 'TP1_HIT') updateData.resolved_at = new Date().toISOString();

    try {
      await fetch('https://ufozbadhugdpaukvvitm.supabase.co/rest/v1/signal_tracker?id=eq.' + trade.id, {
        method: 'PATCH',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
        body: JSON.stringify(updateData)
      });
    } catch(e) { errors.push('PATCH ' + trade.id + ': ' + e.message); }

    closedTrades.push({ coin: trade.coin, dir: trade.direction, type: trade.signal_type, status: newStatus, pnl: pnl.toFixed(2) + '%' });
  }
}

return [{ json: { closedTrades, openCount: trades.length - closedTrades.length, errors } }];
